const body = $input.first().json.body || $input.first().json;
const { monsters, party, terrain, hardcore } = body;

const td = {
  'open-field': 'Open Grassland — no cover, full movement, AOE hits all clustered targets',
  'dungeon': 'Stone Dungeon — 10-ft corridors, AOE limited to adjacent squares, retreat difficult',
  'forest': 'Dense Forest — half-cover available, difficult terrain, chokepoints'
};

let s = 'TERRAIN: ' + (td[terrain] || terrain) + '

=== MONSTERS ===
';
for (const m of (monsters || [])) {
  s += '
--- ' + m.name + ' (CR ' + m.cr + ') ---
HP: ' + m.hp + ' | AC: ' + m.ac + '
';
  s += 'STR:' + (m.str||10) + ' DEX:' + (m.dex||10) + ' CON:' + (m.con||10) + ' INT:' + (m.int||10) + ' WIS:' + (m.wis||10) + ' CHA:' + (m.cha||10) + '
';
  if (m.save && Object.keys(m.save).length) s += 'Saves: ' + Object.entries(m.save).map(([k,v]) => k.toUpperCase() + ' +' + (v||0)).join(', ') + '
';
  if (m.immune?.length) s += 'Damage Immunities: ' + [...m.immune].join(', ') + '
';
  if (m.resist?.length) s += 'Resistances: ' + [...m.resist].join(', ') + '
';
  if (m.conditionImmune?.length) s += 'Condition Immunities: ' + [...m.conditionImmune].join(', ') + '
';
  if (m.trait?.length) { s += 'TRAITS:
'; m.trait.forEach(t => s += '  ' + t + '
'); }
  if (m.allActions?.length) { s += 'ACTIONS:
'; m.allActions.forEach(a => s += '  ' + a + '
'); }
  if (m.reactions?.length) { s += 'REACTIONS:
'; m.reactions.forEach(r => s += '  ' + r + '
'); }
  if (m.legendaryActions?.length) { s += 'LEGENDARY ACTIONS (3 uses/round, spend at end of any other creature's turn):
'; m.legendaryActions.forEach(la => s += '  ' + la + '
'); }
  if (m.breathWeapon) s += 'BREATH WEAPON: ' + m.breathWeapon.name + ' — ' + m.breathWeapon.damage + ' ' + m.breathWeapon.dmgType + ' damage, DC ' + m.breathWeapon.dc + ' DEX save, Recharge 5-6
';
}
s += '
=== PARTY ===
';
for (const pc of (party || [])) {
  s += '
--- ' + pc.name + ' (' + pc.class + ' Lv' + (pc.level||5) + ') ---
HP: ' + pc.hp_max + ' | AC: ' + pc.ac + '
';
  s += 'Attack: +' + (pc.atk||0) + ' to hit | ' + (pc.dmgDice||'1d8') + '+' + (pc.dmgMod||0) + ' | ' + (pc.multi||1) + ' attacks/turn
';
  if (pc.spellDc) s += 'Spell Save DC: ' + pc.spellDc + '
';
  if (pc.subclass) s += 'Subclass: ' + pc.subclass + '
';
  if (pc.features?.length) { s += 'CLASS FEATURES:
'; pc.features.forEach(f => s += '  ' + f.name + ': ' + f.uses + ' uses' + (f.damage ? ', ' + f.damage : '') + '
'); }
}

const systemPrompt = `You are a D&D 5e rules engine. Run this combat with MAXIMUM mechanical accuracy.

RULES:
- Use ALL monster abilities: spells (casters cast their spells!), reactions (Shield, Counterspell, Parry, Opportunity Attacks), ACTUAL legendary action options listed (do NOT just do generic attacks), breath weapons with Recharge 5-6 (roll 1d6 each turn, use on 5-6), lair actions at initiative 20
- Monsters use smart tactics: focus fire weakest target, AOE when enemies clustered, use frightening presence, use reactions when triggered
- PCs use all class features: spell slots, bonus actions, Action Surge, Rage, Hunter's Mark, etc.
- Apply resistances, immunities, conditions (stunned=skip turn, frightened=can't approach, prone=disadvantage+adv against)
- Death saves: nat20=wake at 1HP, nat1=2 failures, 10+=1 success, 3 successes=stable (no more saves), 3 failures=dead

OUTPUT FORMAT — output ONLY this block, no other text:
[RESULT]
OUTCOME: WIN|LOSS|TPK
ROUNDS: <number>
MONSTERS_KILLED: <killed>/<total>
<one line per PC>
PC_<NAME>: ALIVE|DEAD|STABLE|HP:<remaining>|DOWNED:<times>|FU:<Feature×count,...>
[/RESULT]`;

return [{ json: { systemPrompt, userMessage: s } }];

const item = $input.first().json;
const text = item.choices?.[0]?.message?.content || '';
return [{ json: { structured: text } }];
